import socket
import json

class GameServer:
    def __init__(self):
        self.server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server.bind(('', 1234))
        self.players = {}
        self.game_state = {}

    def handle_query(self, data):
        if data == b'status':
            return json.dumps({'players': list(self.players), 'game_state': self.game_state}).encode()
        else:
            return b''

    def start(self):
        while True:
            data, addr = self.server.recvfrom(1024)
            response = self.handle_query(data)
            self.server.sendto(response, addr)